mapper.select:
WITH seeds AS ( SELECT document_id, chunk_index FROM document_chunks WHERE workspace_id = #{workspaceId} AND id IN
#{chunkId}
) SELECT DISTINCT chunk.id AS chunk_id, chunk.document_id, chunk.chunk_index, document.file_name, chunk.chunk_text AS text FROM document_chunks AS chunk JOIN documents AS document ON document.id = chunk.document_id AND document.workspace_id = #{workspaceId} WHERE chunk.workspace_id = #{workspaceId} AND chunk.status = 'READY' AND chunk.deleted = FALSE AND document.status = 'READY' AND EXISTS ( SELECT 1 FROM seeds WHERE seeds.document_id = chunk.document_id AND chunk.chunk_index BETWEEN seeds.chunk_index - #{radius} AND seeds.chunk_index + #{radius} ) ORDER BY chunk.document_id, chunk.chunk_index
